$string['cohort_card_balance_diagnostic'] = 'Cohort LMS activity over the past 30 days is heavily skewed towards content consumption ({$a->content}%) with minimal peer engagement ({$a->engagement}%). Assessment activity is at {$a->assessment}% and administrative actions at {$a->admin}%. Dawson (2006) found that balanced activity profiles — particularly those including engagement and assessment — are associated with stronger learning outcomes.';
$string['cohort_card_balance_title'] = 'Imbalanced course activity profile';
$string['cohort_card_compound_action'] = '{$a->names} need urgent, individualised outreach. Schedule one-on-one check-ins with each to understand barriers and co-create a recovery plan. Peer mentoring or study groups may also help re-engage them socially.';
$string['cohort_card_compound_diagnostic'] = '{$a->count} students are both socially isolated (forum participation below {$a->spthreshold}%) and academically below the {$a->passmark}% pass mark. This combination is the strongest predictor of withdrawal in online courses.';
$string['cohort_card_compound_title'] = 'Compound risk: isolation + failing';
$string['cohort_card_engagement_action'] = '{$a->count} students have engaged with fewer than 20% of the {$a->activities} available course activities. Review whether materials are accessible and clearly sequenced. Consider posting a brief announcement highlighting key activities, or adding low-stakes activities that prompt engagement.';
$string['cohort_card_engagement_diagnostic'] = '{$a->percent}% of the cohort ({$a->count} students) has minimal engagement with course activities (trigger: ≥{$a->threshold}% at low engagement). The course has {$a->activities} trackable activities. Widespread low engagement may indicate structural barriers, unclear expectations, or content that is not reaching students.';
$string['cohort_card_engagement_title'] = 'Widespread low course engagement';
$string['cohort_card_failing_action'] = 'Review assessment design and marking criteria for the {$a} students below 50%. Consider targeted support: revision workshops, additional resources, or early feedback opportunities on upcoming assessments.';
$string['cohort_card_failing_diagnostic'] = '{$a->count} students ({$a->percent}%) are currently below the {$a->passmark}% pass mark (class average: {$a->average}%; trigger: ≥{$a->threshold}% failing). A high failure rate may point to misaligned expectations, insufficient scaffolding, or a need for formative assessment earlier in the course.';
$string['cohort_card_failing_title'] = 'High failure rate';
$string['cohort_card_feedback_action'] = '{$a} students have not reviewed their graded feedback. Send them a targeted message highlighting specific feedback they should review, or dedicate class time to a guided feedback-review activity.';
$string['cohort_card_feedback_diagnostic'] = '{$a->percent}% of the cohort ({$a->count} students) has not engaged with teacher feedback (trigger: ≥{$a->threshold}% at low feedback review). When feedback goes unreviewed, the teaching presence loop is broken — students miss targeted guidance and tend to repeat the same mistakes.';
$string['cohort_card_feedback_title'] = 'Low feedback engagement';
$string['cohort_card_isolation_action'] = '{$a->count} students need social engagement support. With {$a->threads} discussion threads available, consider introducing structured peer interaction: discussion prompts that require responses, small group activities, or peer review tasks.';
$string['cohort_card_isolation_diagnostic'] = '{$a->percent}% of the cohort ({$a->count} students) has minimal or no forum participation across the {$a->total} course discussion threads (trigger: ≥{$a->threshold}% at low social presence). Widespread social isolation weakens the learning community and reduces opportunities for collaborative knowledge construction.';
$string['cohort_card_isolation_silent'] = 'Of these, {$a->silent} are "silent learners" who read discussions but do not post (Macfadyen & Dawson, 2012: r=.95), while {$a->disengaged} show no reading activity at all. Silent learners may benefit from low-barrier participation prompts (e.g., reactions, polls) rather than requiring full posts.';
